const CURVES = [
  {id:'a',eqn:'y² = x³ − x',     A:-1, B:0, rank:0,tors:'Z/2 ⊕ Z/2',gen:null, pts2:[[-1,0],[0,0],[1,0]],note:'rank 0; only 2-torsion'},
  {id:'b',eqn:'y² = x³ + 1',     A:0, B:1,  rank:0,tors:'Z/6',      gen:[2,3],pts2:[[-1,0]],note:'rank 0; (2,3) is a 6-torsion generator'},
  {id:'c',eqn:'y² = x³ − x + 1', A:-1,B:1,  rank:1,tors:'trivial',  gen:[0,1],pts2:[],note:'rank 1; P = (0,1) generates E(Q)'},
  {id:'d',eqn:'y² = x³ − 7',     A:0, B:-7, rank:0,tors:'trivial',  gen:null, pts2:[],note:'rank 0; no non-identity rational points'},
  {id:'e',eqn:'y² = x³ + 17',    A:0, B:17, rank:2,tors:'trivial',  gen:[-2,3],pts2:[],note:'rank 2; P₁=(−2,3), P₂=(−1,4) independent'},
  {id:'f',eqn:'y² = x³ − 82x',   A:-82,B:0, rank:1,tors:'Z/2',      gen:[-9,24],pts2:[[0,0]],note:'rank 1 congruent-number curve'},
];

const pick = $('#mw-pick'), svg = $('#mw-svg'), out = $('#mw-out');
const dblBtn = $('#mw-double'), rst = $('#mw-reset');
CURVES.forEach(c => {
  const o = document.createElement('option');
  o.value = c.id; o.textContent = c.eqn + '   (rank ' + c.rank + ')';
  pick.appendChild(o);
});
let cur = CURVES[0], P = null;

function setCurve(id){
  cur = CURVES.find(c => c.id === id);
  P = cur.gen ? [cur.gen[0], cur.gen[1]] : null;
  draw();
}

function doubleP(){
  if(!P) return;
  const [x,y] = P; if(y === 0) return;
  const lam = (3*x*x + cur.A) / (2*y);
  const xr  = lam*lam - 2*x;
  const yr  = lam*(x - xr) - y;
  P = [xr, yr];
  draw();
}

function curvePoints(A, B, xmin, xmax, N){
  const top = [], bot = [];
  const f = x => x*x*x + A*x + B;
  for(let i=0;i<=N;i++){
    const x = xmin + (xmax-xmin)*i/N;
    const v = f(x);
    if(v >= 0){
      const y = Math.sqrt(v);
      top.push([x, y]); bot.push([x,-y]);
    } else {
      if(top.length){ top.push(null); bot.push(null); }
    }
  }
  return {top, bot};
}

function splitBranches(arr){
  const out = []; let cur = [];
  for(const p of arr){
    if(p === null){ if(cur.length) out.push(cur); cur = []; }
    else cur.push(p);
  }
  if(cur.length) out.push(cur);
  return out;
}

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=320, pad=34;
  const xmin=-5, xmax=5, ymin=-8, ymax=8;
  const X = x => pad + (x-xmin)*(W-2*pad)/(xmax-xmin);
  const Y = y => H-pad - (y-ymin)*(H-2*pad)/(ymax-ymin);
  // axes
  svg.appendChild(SVG('line',{x1:pad,y1:Y(0),x2:W-pad,y2:Y(0),stroke:'var(--line)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:X(0),y1:pad,x2:X(0),y2:H-pad,stroke:'var(--line)','stroke-width':1}));
  for(let k=xmin; k<=xmax; k++){
    svg.appendChild(SVG('line',{x1:X(k),y1:Y(0)-3,x2:X(k),y2:Y(0)+3,stroke:'var(--mute)'}));
  }
  // curve (real locus)
  const {top, bot} = curvePoints(cur.A, cur.B, xmin, xmax, 400);
  const toPath = branch => 'M ' + branch.map(([x,y]) => X(x)+' '+Y(y)).join(' L ');
  for(const b of splitBranches(top)){
    if(b.length<2) continue;
    svg.appendChild(SVG('path',{d:toPath(b),fill:'none',stroke:'var(--cyan)','stroke-width':2}));
  }
  for(const b of splitBranches(bot)){
    if(b.length<2) continue;
    svg.appendChild(SVG('path',{d:toPath(b),fill:'none',stroke:'var(--cyan)','stroke-width':2}));
  }
  // 2-torsion markers
  for(const [x,y] of cur.pts2){
    if(x < xmin || x > xmax) continue;
    svg.appendChild(SVG('circle',{cx:X(x),cy:Y(y),r:4,fill:'var(--pink)'}));
  }
  // generator P and 2P
  if(P && isFinite(P[0]) && isFinite(P[1]) && P[0] >= xmin && P[0] <= xmax && P[1] >= ymin && P[1] <= ymax){
    svg.appendChild(SVG('circle',{cx:X(P[0]),cy:Y(P[1]),r:5,fill:'var(--yellow)'}));
    const t = SVG('text',{x:X(P[0])+8,y:Y(P[1])-6,'font-size':12,fill:'var(--yellow)'});
    t.textContent = '('+P[0].toFixed(3)+', '+P[1].toFixed(3)+')';
    svg.appendChild(t);
  }
  // equation label
  const lab = SVG('text',{x:W-pad,y:pad-8,'text-anchor':'end','font-size':13,fill:'var(--mute)'});
  lab.textContent = cur.eqn;
  svg.appendChild(lab);

  // readout
  const lines = [];
  lines.push('E(Q) ≅ Z^' + cur.rank + (cur.tors==='trivial' ? '' : ' ⊕ ' + cur.tors));
  lines.push(cur.note);
  if(P){
    lines.push('P = ('+P[0].toFixed(4)+', '+P[1].toFixed(4)+')');
  } else {
    lines.push('no infinite-order generator on this curve');
  }
  out.textContent = lines.join('\n');
}

pick.addEventListener('change', () => setCurve(pick.value));
dblBtn.addEventListener('click', doubleP);
rst.addEventListener('click', () => { P = cur.gen ? [cur.gen[0], cur.gen[1]] : null; draw(); });
setCurve('a');

