setCurve('a');

// BigInt rational arithmetic. All (x,y) kept as pairs of Frac = {n, d} with d > 0.
const B = BigInt;
function absB(x){ return x<0n ? -x : x; }
function gcdB(a,b){ a=absB(a); b=absB(b); while(b){ [a,b]=[b,a%b]; } return a||1n; }
function F(n,d){
  if(typeof n!=='bigint') n=B(n);
  if(typeof d!=='bigint') d=B(d);
  if(d===0n) throw new Error('div0');
  if(d<0n){ n=-n; d=-d; }
  const g = gcdB(n,d);
  return { n: n/g, d: d/g };
}
const add = (a,b) => F(a.n*b.d + b.n*a.d, a.d*b.d);
const sub = (a,b) => F(a.n*b.d - b.n*a.d, a.d*b.d);
const mul = (a,b) => F(a.n*b.n, a.d*b.d);
const divF = (a,b) => F(a.n*b.d, a.d*b.n);
const neg = (a) => F(-a.n, a.d);
const eqF = (a,b) => a.n*b.d === b.n*a.d;
const toFloat = a => Number(a.n) / Number(a.d);
function fmt(a){
  if(a.d === 1n) return String(a.n);
  // if numerator and denominator both small, print as fraction
  if(absB(a.n) < 100000n && a.d < 100000n) return a.n + '/' + a.d;
  // otherwise truncate magnitude
  const fl = toFloat(a);
  if(!isFinite(fl)) return '(overflow)';
  return fl.toExponential(6);
}
// y² = x³ + Ax + B with A=0, B=−2
const A = F(0,1), Bc = F(-2,1);
// Group law using chord (secant) and tangent rules.
function addPts(P, Q){
  if(P === null) return Q;
  if(Q === null) return P;
  // vertical? same x, opposite y => O
  if(eqF(P.x, Q.x)){
    if(eqF(P.y, neg(Q.y))) return null; // infinity
    if(!eqF(P.y, Q.y)) return null;
    // P == Q : tangent doubling
    if(P.y.n === 0n) return null;
    // λ = (3x² + A) / (2y)
    const num = add(mul(F(3,1), mul(P.x, P.x)), A);
    const den = mul(F(2,1), P.y);
    const lam = divF(num, den);
    const xr = sub(sub(mul(lam, lam), P.x), Q.x);
    const yr = sub(mul(lam, sub(P.x, xr)), P.y);
    return { x: xr, y: yr };
  }
  // chord
  const lam = divF(sub(Q.y, P.y), sub(Q.x, P.x));
  const xr = sub(sub(mul(lam, lam), P.x), Q.x);
  const yr = sub(mul(lam, sub(P.x, xr)), P.y);
  return { x: xr, y: yr };
}

const P0 = { x: F(3,1), y: F(5,1) };  // (3, 5) on y² = x³ − 2 ; 27 + (−2) = 25 = 5²
let history = [P0];
const svg = $('#ct-svg'), out = $('#ct-out');
const btn = $('#ct-step'), rst = $('#ct-reset'), opSel = $('#ct-op');

function step(){
  const cur = history[history.length-1];
  if(cur === null) return;
  const op = opSel.value;
  let nxt;
  try {
    if(op === 'double'){ nxt = addPts(cur, cur); }
    else { nxt = addPts(cur, P0); }
  } catch(e){ nxt = null; }
  history.push(nxt);
  if(history.length > 6) history = history.slice(-6);
  draw();
}
function reset(){ history = [P0]; draw(); }

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=340, pad=36;
  const xmin=-2, xmax=7, ymin=-13, ymax=13;
  const X = x => pad + (x-xmin)*(W-2*pad)/(xmax-xmin);
  const Y = y => H-pad - (y-ymin)*(H-2*pad)/(ymax-ymin);
  // axes
  svg.appendChild(SVG('line',{x1:pad,y1:Y(0),x2:W-pad,y2:Y(0),stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:X(0),y1:pad,x2:X(0),y2:H-pad,stroke:'var(--line)'}));
  // tick labels
  for(let k=-1; k<=6; k++){
    svg.appendChild(SVG('line',{x1:X(k),y1:Y(0)-3,x2:X(k),y2:Y(0)+3,stroke:'var(--mute)'}));
  }
  // curve y² = x³ − 2: need x³ ≥ 2, x ≥ 2^{1/3} ≈ 1.2599
  const top=[], bot=[];
  const xStart = Math.cbrt(2);
  for(let i=0;i<=400;i++){
    const x = xStart + (xmax - xStart) * i/400;
    const rhs = x*x*x - 2;
    if(rhs < 0) continue;
    const y = Math.sqrt(rhs);
    top.push([x, y]); bot.push([x, -y]);
  }
  const topPath = 'M ' + top.map(([x,y]) => X(x)+' '+Y(y)).join(' L ');
  const botPath = 'M ' + bot.map(([x,y]) => X(x)+' '+Y(y)).join(' L ');
  svg.appendChild(SVG('path',{d:topPath,fill:'none',stroke:'var(--cyan)','stroke-width':2}));
  svg.appendChild(SVG('path',{d:botPath,fill:'none',stroke:'var(--cyan)','stroke-width':2}));

  // render history[k]: the secant/tangent used to build it, third point, reflection
  const op = opSel.value;
  for(let k=1; k<history.length; k++){
    const Qn = history[k];
    if(Qn === null) continue;
    const Pprev = history[k-1];
    if(Pprev === null) continue;
    // the line is between Pprev and (op==='step' ? P0 : Pprev). third intersection is (x3, -y3_reflected)
    const Partner = (op === 'double') ? Pprev : P0;
    // only draw if Qn in view
    const xq = toFloat(Qn.x), yq = toFloat(Qn.y);
    if(!isFinite(xq) || !isFinite(yq)) continue;
    // slope
    let lam;
    if(eqF(Pprev.x, Partner.x)){
      const num = add(mul(F(3,1), mul(Pprev.x, Pprev.x)), A);
      const den = mul(F(2,1), Pprev.y);
      lam = divF(num, den);
    } else {
      lam = divF(sub(Partner.y, Pprev.y), sub(Partner.x, Pprev.x));
    }
    const lamF = toFloat(lam);
    const px = toFloat(Pprev.x), py = toFloat(Pprev.y);
    // draw secant / tangent through Pprev with slope lamF, across visible x-range
    const yAtXmin = py + lamF*(xmin - px);
    const yAtXmax = py + lamF*(xmax - px);
    const fade = Math.max(0.18, 0.9 - (history.length-1-k)*0.15);
    svg.appendChild(SVG('line',{x1:X(xmin),y1:Y(yAtXmin),x2:X(xmax),y2:Y(yAtXmax),
      stroke:'var(--blue)','stroke-width':1.1,'stroke-dasharray':'4 3',opacity:fade}));
    // third intersection is (x3, -y3) — reflection bridge
    const x3 = xq, y3neg = -yq;
    if(isFinite(x3) && isFinite(y3neg) && x3>=xmin && x3<=xmax && y3neg>=ymin && y3neg<=ymax){
      svg.appendChild(SVG('line',{x1:X(x3),y1:Y(y3neg),x2:X(x3),y2:Y(yq),
        stroke:'var(--pink)','stroke-width':1,'stroke-dasharray':'2 3',opacity:fade}));
      svg.appendChild(SVG('circle',{cx:X(x3),cy:Y(y3neg),r:3,fill:'var(--mute)',opacity:fade}));
    }
  }

  // dots
  history.forEach((pt, k) => {
    if(pt === null) return;
    const x = toFloat(pt.x), y = toFloat(pt.y);
    if(!isFinite(x) || !isFinite(y)) return;
    if(x < xmin || x > xmax || y < ymin || y > ymax) return;
    const isGen = (k===0);
    svg.appendChild(SVG('circle',{cx:X(x),cy:Y(y),r:isGen?6:4.5,
      fill:isGen?'var(--yellow)':'var(--green)'}));
    const t = SVG('text',{x:X(x)+8, y:Y(y)-6,'font-size':12,
      fill:isGen?'var(--yellow)':'var(--green)'});
    t.textContent = isGen ? 'P' : (opSel.value === 'double' && k>0 ? '2^'+k+'·P' : (k+1)+'P');
    svg.appendChild(t);
  });

  const eqn = SVG('text',{x:W-pad,y:pad-8,'text-anchor':'end','font-size':13,fill:'var(--mute)'});
  eqn.textContent = 'y² = x³ − 2'; svg.appendChild(eqn);

  // readout
  const lines = [];
  lines.push('generator  P = (3, 5)   on  E : y² = x³ − 2');
  lines.push('E(Q) ≅ Z · P   (rank 1, trivial torsion; proved by 2-descent)');
  for(let k=0;k<history.length;k++){
    const pt = history[k];
    const lbl = (k===0) ? 'P' : (opSel.value==='double' ? '2^'+k+'·P' : (k+1)+'P');
    if(pt === null){ lines.push(lbl + ' = O  (point at infinity)'); continue; }
    const xf = fmt(pt.x), yf = fmt(pt.y);
    const lh = Math.log10(Math.max(1, Number(absB(pt.x.n)), Number(pt.x.d)));
    lines.push(lbl + ' = (' + xf + ',  ' + yf + ')   [log₁₀ |num/den| ≈ ' + lh.toFixed(2) + ']');
  }
  out.textContent = lines.join('\n');
}

btn.addEventListener('click', step);
rst.addEventListener('click', reset);
opSel.addEventListener('change', reset);
draw();

