const CURVES = [
  { A:-1, B:0,  rank:0, bad:new Set([2]) },
  { A:0,  B:1,  rank:0, bad:new Set([2,3]) },
  { A:-1, B:1,  rank:1, bad:new Set([2,11]) },
  { A:0,  B:17, rank:2, bad:new Set([2,3,17]) },
];
const PMAX = 2000;
// sieve of primes up to PMAX
const primes = (()=>{
  const sv = new Uint8Array(PMAX+1);
  for(let i=2;i<=PMAX;i++){
    if(!sv[i]){
      for(let j=i*i;j<=PMAX;j+=i) sv[j]=1;
    }
  }
  const out=[]; for(let i=2;i<=PMAX;i++) if(!sv[i]) out.push(i); return out;
})();

const modp = (a,m) => ((a%m)+m)%m;
function powmod(a,e,m){
  let r=1n; a=BigInt(modp(a,m)); e=BigInt(e); const M=BigInt(m);
  while(e>0n){ if(e&1n) r=(r*a)%M; a=(a*a)%M; e>>=1n; }
  return Number(r);
}
function countNp(A,B,p){
  let N=1;
  for(let x=0;x<p;x++){
    const rhs = modp(x*x%p*x + A*x + B, p);
    if(rhs===0) N+=1;
    else if(powmod(rhs,(p-1)/2,p)===1) N+=2;
  }
  return N;
}

// precompute ap per curve
const apCache = CURVES.map(C => {
  const arr = new Int32Array(primes.length);
  for(let i=0;i<primes.length;i++){
    const p = primes[i];
    if(C.bad.has(p)){ arr[i] = 99999; continue; } // sentinel
    const Np = countNp(C.A, C.B, p);
    arr[i] = p + 1 - Np;
  }
  return arr;
});

const pick = $('#pc-pick'), xs = $('#pc-X'), svg = $('#pc-svg'), out = $('#pc-out'), xv = $('#pc-xval');

function draw(){
  const ci = +pick.value;
  const X = +xs.value;
  xv.textContent = 'X = ' + X;
  const ap = apCache[ci];
  const pts = []; // (log X_p, log Pi)
  let logPi = 0;
  for(let i=0;i<primes.length;i++){
    const p = primes[i]; if(p > X) break;
    if(CURVES[ci].bad.has(p)) continue;
    const a = ap[i];
    // factor = N_p / p = 1 - a/p + 1/p
    const f = 1 - a/p + 1/p;
    if(f <= 0) continue;
    logPi += Math.log(f);
    pts.push([Math.log(p), logPi]);
  }
  const Pi = Math.exp(logPi);
  // least-squares fit of logPi vs log(log p) using tail (skip early noisy points)
  let slope = NaN;
  if(pts.length > 20){
    const tail = pts.slice(Math.floor(pts.length*0.3));
    const n = tail.length;
    let sx=0, sy=0, sxx=0, sxy=0;
    for(const [lp, lPi] of tail){
      const u = Math.log(lp); // log log p
      sx+=u; sy+=lPi; sxx+=u*u; sxy+=u*lPi;
    }
    slope = (n*sxy - sx*sy)/(n*sxx - sx*sx);
  }

  // render
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=300, pad=36;
  if(!pts.length){ out.textContent = 'need more primes'; return; }
  const xmin = pts[0][0], xmax = pts[pts.length-1][0];
  const ymin = Math.min(0, ...pts.map(p=>p[1])) - 0.2;
  const ymax = Math.max(0.2, ...pts.map(p=>p[1])) + 0.2;
  const X2 = u => pad + (u - xmin) * (W - 2*pad) / (xmax - xmin || 1);
  const Y2 = u => H - pad - (u - ymin) * (H - 2*pad) / (ymax - ymin || 1);
  // axes
  svg.appendChild(SVG('line',{x1:pad,y1:Y2(0),x2:W-pad,y2:Y2(0),stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:pad,y1:pad,x2:pad,y2:H-pad,stroke:'var(--line)'}));
  // polyline
  const d = 'M ' + pts.map(([u,v]) => X2(u)+' '+Y2(v)).join(' L ');
  svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':1.8}));
  // axis labels
  const lx = SVG('text',{x:W-pad,y:H-8,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
  lx.textContent = 'log p  →'; svg.appendChild(lx);
  const ly = SVG('text',{x:pad+6,y:pad+4,'font-size':12,fill:'var(--mute)'});
  ly.textContent = 'log Π(X)'; svg.appendChild(ly);

  const r = CURVES[ci].rank;
  const slopeStr = isFinite(slope) ? slope.toFixed(3) : '—';
  out.textContent =
    'curve rank r = ' + r + '\n' +
    'Π(' + X + ')  = ' + Pi.toFixed(4) + '      log Π = ' + logPi.toFixed(4) + '\n' +
    'good primes used: ' + pts.length + '\n' +
    'fit slope of log Π vs log log X  ≈  ' + slopeStr + '   (BSD predicts ≈ ' + r + ')';
}

