const MODELS = {
  0:{c:0.92,a:0.30,note:'L(E,1) ≠ 0 ⇒ rank 0 (Kolyvagin ⇒ BSD holds)'},
  1:{c:1.05,a:-0.20,note:'simple zero at s=1 ⇒ rank 1 (Kolyvagin + Gross–Zagier)'},
  2:{c:0.80,a:0.15,note:'double zero at s=1 ⇒ rank 2 (BSD still open in general)'},
};
let r = 1;
const svg = $('#Lz-svg'), out = $('#Lz-out');
const btns = $$('.rk', $('#w-Lz'));

function Lmod(s, rr){
  const M = MODELS[rr];
  return M.c * Math.pow(s - 1, rr) * (1 + M.a*(s-1));
}

function draw(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=280, pad=36;
  const smin=0.3, smax=1.7;
  const X = s => pad + (s-smin)*(W-2*pad)/(smax-smin);
  // sample curve
  const vals = [];
  for(let i=0;i<=400;i++){
    const s = smin + (smax-smin)*i/400;
    vals.push([s, Lmod(s, r)]);
  }
  let ymin = Math.min(0, ...vals.map(v=>v[1]));
