];
// short Weierstrass reduction: E : y²+a1xy+a3y = x³+a2x²+a4x+a6 ⇒ rhs-count mod p.
const PMAX = 400;
const primes = (()=>{
  const sv = new Uint8Array(PMAX+1);
  for(let i=2;i<=PMAX;i++){ if(!sv[i]){ for(let j=i*i;j<=PMAX;j+=i) sv[j]=1; } }
  const out=[]; for(let i=2;i<=PMAX;i++) if(!sv[i]) out.push(i); return out;
})();
function apFor(A, p){
  // a1,a2,a3,a4,a6
  const [a1,a2,a3,a4,a6] = A;
  const mod = (a,m)=>((a%m)+m)%m;
  // N_p = #{(x,y) ∈ F_p² : y²+a1xy+a3y ≡ x³+a2x²+a4x+a6} + 1 (point at infinity)
  let N = 1;
  for(let x=0;x<p;x++){
    const rhs = mod(x*x%p*x + a2*x*x + a4*x + a6, p);
    for(let y=0;y<p;y++){
      const lhs = mod(y*y + a1*x*y + a3*y, p);
      if(lhs === rhs) N++;
    }
  }
  return p + 1 - N;
}

