// Sample a truncated L near s=1
function Ltrunc(apArr, s, X){
  // L(E,s) ≈ ∏_{p ≤ X, p good} (1 − a_p p^{−s} + p^{1−2s})^{−1}
  let prod = 1;
  for(let i=0;i<primes.length;i++){
    const p = primes[i]; if(p > X) break;
    const ap = apArr[i];
    if(ap == null || !isFinite(ap)) continue; // bad prime
    const f = 1 - ap * Math.pow(p, -s) + Math.pow(p, 1 - 2*s);
    if(Math.abs(f) < 1e-12) return NaN;
    prod *= 1/f;
  }
  return prod;
}

function draw(){
  const idx = +pick.value;
  const c = CURVES[idx];
  // compute a_p for p up to PMAX (skip p | N by sentinel)
  const apArr = primes.map(p => (c.N % p === 0) ? null : apFor(c.A, p));

  // probe L(1+h) for a grid of h values; fit slope of log|L| vs log|h| to estimate r
  const hs = [0.05, 0.08, 0.12, 0.18, 0.25, 0.35];
  const probed = hs.map(h => ({ h, L: Ltrunc(apArr, 1 + h, 150) }));
  // only use points where L stayed positive
  const good = probed.filter(p => p.L > 0 && isFinite(p.L));
  let fitR = NaN;
  if(good.length >= 3){
    const pts = good.map(p => [Math.log(p.h), Math.log(p.L)]);
    let sx=0,sy=0,sxx=0,sxy=0,n=pts.length;
    for(const [x,y] of pts){ sx+=x; sy+=y; sxx+=x*x; sxy+=x*y; }
    fitR = (n*sxy - sx*sy) / (n*sxx - sx*sx);
  }

  // draw L(1+h) vs h
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=300, pad=40;
  // sample curve for -0.4..0.4
  const HS=[]; for(let i=0;i<=120;i++) HS.push(-0.4 + 0.8*i/120);
  const vals = HS.map(h => ({h, L: Ltrunc(apArr, 1 + h, 150)}));
  const ls = vals.map(v=>v.L).filter(v=>isFinite(v));
  const ymin = Math.min(0, ...ls) - 0.3, ymax = Math.max(0, ...ls) + 0.3;
  const xmin = -0.4, xmax = 0.4;
  const X = x => pad + (x-xmin)*(W-2*pad)/(xmax-xmin);
  const Y = y => H-pad - (y-ymin)*(H-2*pad)/(ymax-ymin);
  // axes
  svg.appendChild(SVG('line',{x1:pad,y1:Y(0),x2:W-pad,y2:Y(0),stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:X(0),y1:pad,x2:X(0),y2:H-pad,stroke:'var(--violet)','stroke-dasharray':'4 4'}));
  // L curve
  const pathSegs = [];
  let cur = null;
  for(const v of vals){
    if(isFinite(v.L)){ if(!cur){ cur='M'; } else { cur=' L'; } pathSegs.push(cur + X(v.h) + ' ' + Y(v.L)); }
    else { cur = null; }
  }
  svg.appendChild(SVG('path',{d:pathSegs.join(''),fill:'none',stroke:'var(--yellow)','stroke-width':2}));
  // zero at s=1 (h=0)
  const L1 = Ltrunc(apArr, 1, 150);
  if(isFinite(L1)){
    svg.appendChild(SVG('circle',{cx:X(0),cy:Y(L1),r:5,fill:'var(--pink)'}));
  }
  // probe dots
  good.forEach(p => {
    svg.appendChild(SVG('circle',{cx:X(p.h),cy:Y(p.L),r:3,fill:'var(--green)'}));
  });
  // labels
  const tx = SVG('text',{x:W-pad,y:H-10,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
  tx.textContent = 'h = s − 1  →'; svg.appendChild(tx);
  const ty = SVG('text',{x:pad+4,y:pad+10,'font-size':12,fill:'var(--mute)'});
  ty.textContent = 'L(E, 1 + h)'; svg.appendChild(ty);
  const eqn = SVG('text',{x:W-pad,y:pad+10,'text-anchor':'end','font-size':12,fill:'var(--cyan)'});
  eqn.textContent = 'conductor N = ' + c.N; svg.appendChild(eqn);

  const lines = [];
  lines.push(c.label);
  lines.push('partial Euler product truncated at X = 150 (' + primes.filter(p=>p<=150).length + ' primes used)');
  const slopeStr = isFinite(fitR) ? fitR.toFixed(2) : '—';
  lines.push('analytic rank ≈ ' + slopeStr + '   (fit slope of log|L(1+h)| vs log|h|, h ≤ 0.35)');
  lines.push('algebraic rank = ' + c.gRank + '   generators: ' + (c.gens.length ? c.gens.join(', ') : '(none of infinite order)'));
  lines.push('torsion: ' + c.tors);
  const agree = (Math.round(isFinite(fitR)?fitR:-1) === c.gRank);
  lines.push('BSD prediction: rank_alg = ' + c.gRank + ' = rank_an   ' + (agree ? '✓ consistent' : '(truncation noisy; expected rank ' + c.aRank + ')'));
  lines.push('leading Taylor coefficient L^{('+c.aRank+')}(E,1)/'+c.aRank+'! ≈ ' + c.Ltay + '   (LMFDB value)');
  lines.push(c.note);
  out.textContent = lines.join('\n');
}

