  eqn.textContent = 'conductor N = ' + c.N; svg.appendChild(eqn);

  const lines = [];
  lines.push(c.label);
  lines.push('partial Euler product truncated at X = 150 (' + primes.filter(p=>p<=150).length + ' primes used)');
  const slopeStr = isFinite(fitR) ? fitR.toFixed(2) : '—';
  lines.push('analytic rank ≈ ' + slopeStr + '   (fit slope of log|L(1+h)| vs log|h|, h ≤ 0.35)');
  lines.push('algebraic rank = ' + c.gRank + '   generators: ' + (c.gens.length ? c.gens.join(', ') : '(none of infinite order)'));
  lines.push('torsion: ' + c.tors);
  const agree = (Math.round(isFinite(fitR)?fitR:-1) === c.gRank);
  lines.push('BSD prediction: rank_alg = ' + c.gRank + ' = rank_an   ' + (agree ? '✓ consistent' : '(truncation noisy; expected rank ' + c.aRank + ')'));
  lines.push('leading Taylor coefficient L^{('+c.aRank+')}(E,1)/'+c.aRank+'! ≈ ' + c.Ltay + '   (LMFDB value)');
  lines.push(c.note);
  out.textContent = lines.join('\n');
}

