const h1=$('#reg-h1'), h2=$('#reg-h2'), c=$('#reg-c');
const h1v=$('#reg-h1v'), h2v=$('#reg-h2v'), cv=$('#reg-cv');
const svg=$('#reg-svg'), out=$('#reg-out');

function draw(){
  const a=+h1.value, b=+h2.value, x=+c.value;
  h1v.textContent=a.toFixed(2); h2v.textContent=b.toFixed(2); cv.textContent=x.toFixed(2);
  const det = a*b - x*x;
  // constraint: Gram must be positive-definite: a>0, det>0
  const pd = det > 0 && a > 0;

  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=260, cx=W/2, cy=H/2;
  // draw the lattice spanned by v1=(√a,0), v2=(x/√a, √(det/a)) if pd
  const scale = 45;
  const v1=[Math.sqrt(a)*scale, 0];
  let v2;
  if(pd){ v2=[x/Math.sqrt(a)*scale, Math.sqrt(det/a)*scale]; }
  else  { v2=[x/Math.sqrt(Math.max(a,1e-3))*scale, 0]; }
  // grid of lattice points
  for(let i=-3;i<=3;i++){
    for(let j=-3;j<=3;j++){
      const px = cx + i*v1[0] + j*v2[0];
      const py = cy - (i*v1[1] + j*v2[1]);
      if(px<10||px>W-10||py<10||py>H-10) continue;
      const isOrigin = (i===0 && j===0);
      svg.appendChild(SVG('circle',{cx:px,cy:py,r:isOrigin?4:2.5,
        fill: isOrigin?'var(--yellow)':'var(--mute)'}));
    }
  }
  // fundamental parallelogram
  if(pd){
    const p0=[cx,cy], p1=[cx+v1[0],cy-v1[1]], p2=[cx+v1[0]+v2[0],cy-v1[1]-v2[1]], p3=[cx+v2[0],cy-v2[1]];
    const poly = [p0,p1,p2,p3].map(p=>p.join(',')).join(' ');
    svg.appendChild(SVG('polygon',{points:poly,fill:'rgba(255,216,102,0.15)',stroke:'var(--yellow)','stroke-width':1.5}));
  }
  // axis
  svg.appendChild(SVG('line',{x1:20,y1:cy,x2:W-20,y2:cy,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)'}));
  // legend
  const t = SVG('text',{x:W-16,y:H-10,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
  t.textContent = pd ? ('covolume √det = '+Math.sqrt(det).toFixed(3)) : 'not positive-definite';
  svg.appendChild(t);

  const lines=[];
  lines.push('Gram matrix  G = [[ '+a.toFixed(2)+', '+x.toFixed(2)+' ], [ '+x.toFixed(2)+', '+b.toFixed(2)+' ]]');
  lines.push('regulator R = det G = '+det.toFixed(4));
  if(pd){
    lines.push('lattice covolume = √R ≈ '+Math.sqrt(det).toFixed(4));
    lines.push('contribution to refined BSD: L^{(r)}(E,1)/r! ∝ Ω·R·|Ш|·∏c_p / |E_tors|²');
  } else {
    lines.push('⚠ pairing is not positive-definite (|⟨P₁,P₂⟩| too large) — pick smaller off-diagonal');
  }
  out.textContent = lines.join('\n');
}

h1.addEventListener('input',draw); h2.addEventListener('input',draw); c.addEventListener('input',draw);
draw();

