const sel=$('#sha-sel'), mw=$('#sha-mw'), nSel=$('#sha-n');
const selv=$('#sha-selv'), mwv=$('#sha-mwv');
const svg=$('#sha-svg'), out=$('#sha-out');

function draw(){
  const S=+sel.value, M=+mw.value, n=+nSel.value;
  selv.textContent=S; mwv.textContent=M;
  const divides = (S%M===0);
  const shaN = divides ? Math.round(S/M) : NaN;

  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=620, H=220;
  // bar A = Sel, bar B = MW part, bar C = Sha[n]
  const scale = 0.9 * (W-120) / Math.max(S, 8);
  const rows = [
    {y:40,  w:S*scale, label:'|Sel_n(E)| = '+S, col:'var(--cyan)'},
    {y:100, w:M*scale, label:'|E(Q)/nE| = '+M, col:'var(--yellow)'},
    {y:160, w:(divides?shaN*scale:0), label:divides?('|Ш(E/Q)[n]| = '+shaN):'size not consistent (|Sel_n| must be a multiple of |E(Q)/nE|)', col:'var(--pink)'},
  ];
  for(const r of rows){
    svg.appendChild(SVG('rect',{x:30,y:r.y,width:Math.max(r.w,1),height:28,
      fill:r.col,opacity:0.7,stroke:r.col,rx:4}));
    const t=SVG('text',{x:40, y:r.y+19,'font-size':13,fill:'#111','font-weight':600});
    t.textContent=r.label; svg.appendChild(t);
  }

  const lines=[];
  lines.push('0 → E(Q)/nE → Sel_n(E) → Ш(E/Q)[n] → 0');
  lines.push('so  |Ш[n]| = |Sel_n| / |E(Q)/nE|  when the quotient is an integer');
  if(divides){
    lines.push('here  |Ш['+n+']| = '+S+' / '+M+' = '+shaN);
    const sq = Math.sqrt(shaN);
    if(Number.isInteger(sq)) lines.push('  ('+shaN+' is a perfect square — consistent with Cassels–Tate)');
    else if(shaN>1) lines.push('  (⚠ '+shaN+' is not a perfect square — for full |Ш| Cassels–Tate forbids this, though |Ш[n]| alone need not be square)');
  } else {
    lines.push('⚠ inconsistent input: Sel_n must contain E(Q)/nE as a subgroup, so |Sel_n| must be divisible by |E(Q)/nE|.');
  }
  out.textContent = lines.join('\n');
}

sel.addEventListener('input',draw); mw.addEventListener('input',draw); nSel.addEventListener('change',draw);
draw();

